from flask import Flask, request, redirect, session
import xml.etree.ElementTree as ET
import base64
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

@app.route('/saml/consume', methods=['POST'])
def consume_saml_response():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return "No SAML Response received", 400

    try:
        decoded_response = base64.b64decode(saml_response)
        root = ET.fromstring(decoded_response)

        # Find the Assertion element
        assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
        if assertion is None:
            return "No Assertion found in SAML Response", 400

        # Extract user attributes
        attributes = {}
        for attribute in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            name = attribute.get('Name')
            value = attribute.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[name] = value

        # Create user session
        session['user'] = attributes
        return redirect('/welcome')

    except Exception as e:
        return f"Error processing SAML Response: {str(e)}", 500

@app.route('/welcome')
def welcome():
    if 'user' not in session:
        return redirect('/')
    return f"Welcome, {session['user'].get('name', 'User')}!"

@app.route('/')
def index():
    return 'SAML SP is running. Please redirect to your IdP for authentication.'

if __name__ == '__main__':
    app.run(ssl_context='adhoc')